            if trade.state not in (TradeState.PENDING, TradeState.ACCEPTED):
                await self.send_to_player(player_id, {
                    "type": "error",
                    "message": "Trade cannot be cancelled in its current state.",
                })
                return

            await self._cancel_trade_internal(trade, f"Cancelled by {player_id}")

